#!/usr/bin/env python3
from pathlib import Path
import base64

ROOT = Path.cwd()

required = [
    "package.json",
    "app",
    "components",
    "public",
]
for rel in required:
    if not (ROOT / rel).exists():
        raise FileNotFoundError(f"No encuentro {rel}. Ejecuta este script desde la raíz del proyecto mundial-porra-2026.")

files = {
    "components/BottomNav.tsx": '"use client";\n\nimport Link from "next/link";\nimport { usePathname } from "next/navigation";\n\nconst items = [\n  { href: "/", label: "Ranking" },\n  { href: "/partidos", label: "Partidos" },\n  { href: "/pronosticos", label: "Quinielas" },\n  { href: "/instalar", label: "Instalar" }\n];\n\nfunction isActive(pathname: string, href: string): boolean {\n  if (href === "/") return pathname === "/";\n  return pathname.startsWith(href);\n}\n\nexport function BottomNav() {\n  const pathname = usePathname();\n\n  return (\n    <nav className="bottom-nav" aria-label="Navegación principal">\n      {items.map((item) => (\n        <Link\n          key={item.href}\n          href={item.href}\n          className={isActive(pathname, item.href) ? "active" : ""}\n        >\n          {item.label}\n        </Link>\n      ))}\n    </nav>\n  );\n}\n',
    "app/layout.tsx": 'import type { Metadata, Viewport } from "next";\nimport { BottomNav } from "@/components/BottomNav";\nimport "./globals.css";\n\nexport const metadata: Metadata = {\n  title: "Mundial 2026",\n  description: "Ranking en directo de Mundial 2026",\n  manifest: "/manifest.json",\n  icons: {\n    icon: [\n      { url: "/favicon-32.png", sizes: "32x32", type: "image/png" },\n      { url: "/icon-192.png", sizes: "192x192", type: "image/png" },\n      { url: "/icon-512.png", sizes: "512x512", type: "image/png" }\n    ],\n    apple: [{ url: "/apple-touch-icon.png", sizes: "180x180", type: "image/png" }]\n  },\n  appleWebApp: {\n    capable: true,\n    title: "Mundial 2026",\n    statusBarStyle: "default"\n  }\n};\n\nexport const viewport: Viewport = {\n  themeColor: "#f8f6f1",\n  width: "device-width",\n  initialScale: 1\n};\n\nexport default function RootLayout({ children }: { children: React.ReactNode }) {\n  return (\n    <html lang="es">\n      <body>\n        <main className="app-shell">{children}</main>\n        <BottomNav />\n      </body>\n    </html>\n  );\n}\n',
    "public/manifest.json": '{\n  "name": "Mundial 2026",\n  "short_name": "Mundial 2026",\n  "description": "Ranking móvil de Mundial 2026",\n  "start_url": "/",\n  "scope": "/",\n  "display": "standalone",\n  "orientation": "portrait",\n  "background_color": "#f8f6f1",\n  "theme_color": "#f8f6f1",\n  "icons": [\n    {\n      "src": "/icon-192.png",\n      "sizes": "192x192",\n      "type": "image/png",\n      "purpose": "any"\n    },\n    {\n      "src": "/icon-512.png",\n      "sizes": "512x512",\n      "type": "image/png",\n      "purpose": "any"\n    },\n    {\n      "src": "/icon-512.png",\n      "sizes": "512x512",\n      "type": "image/png",\n      "purpose": "maskable"\n    }\n  ]\n}\n',
    "app/instalar/page.tsx": 'export default function InstallPage() {\n  return (\n    <section className="screen">\n      <header className="page-header">\n        <div className="section-label">App móvil</div>\n        <h1>Instalar</h1>\n        <p>Añade Mundial 2026 a la pantalla de inicio para abrirla como una app.</p>\n      </header>\n\n      <div className="install-hero-card">\n        <img src="/icon-192.png" alt="Icono Mundial 2026" className="install-icon" />\n        <div>\n          <h2>Mundial 2026</h2>\n          <p>Ranking, partidos y quinielas siempre a mano.</p>\n        </div>\n      </div>\n\n      <section className="install-section">\n        <h2>iPhone / iPad</h2>\n        <ol className="install-steps">\n          <li>Abre esta web en Safari.</li>\n          <li>Toca el botón de compartir.</li>\n          <li>Elige “Añadir a pantalla de inicio”.</li>\n          <li>Confirma con “Añadir”.</li>\n        </ol>\n      </section>\n\n      <section className="install-section">\n        <h2>Android</h2>\n        <ol className="install-steps">\n          <li>Abre esta web en Chrome.</li>\n          <li>Toca el menú de tres puntos.</li>\n          <li>Elige “Añadir a pantalla de inicio” o “Instalar aplicación”.</li>\n          <li>Confirma la instalación.</li>\n        </ol>\n      </section>\n\n      <div className="install-note">\n        Si ya tienes la web abierta en el navegador, la app instalada se actualizará sola con los resultados cuando vuelvas a abrirla.\n      </div>\n    </section>\n  );\n}\n',
}

for rel, content in files.items():
    path = ROOT / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")

icons = {
    "public/icon-192.png": "",
    "public/icon-512.png": "",
    "public/apple-touch-icon.png": "",
    "public/favicon-32.png": "",
}

for rel, data in icons.items():
    path = ROOT / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_bytes(base64.b64decode(data))

css_path = ROOT / "app/globals.css"
if not css_path.exists():
    raise FileNotFoundError("No encuentro app/globals.css")

css = css_path.read_text(encoding="utf-8")
marker = "/* Mobile install page + four-tab navigation */"
if marker not in css:
    css_path.write_text(css.rstrip() + "\n\n" + '/* Mobile install page + four-tab navigation */\n.install-hero-card {\n  display: grid;\n  grid-template-columns: 72px 1fr;\n  gap: 14px;\n  align-items: center;\n  margin-bottom: 18px;\n  padding: 14px;\n  border: 1px solid var(--line);\n  border-radius: 24px;\n  background: var(--surface);\n}\n\n.install-icon {\n  width: 72px;\n  height: 72px;\n  border-radius: 18px;\n  display: block;\n  box-shadow: 0 10px 24px rgba(33, 28, 20, 0.12);\n}\n\n.install-hero-card h2,\n.install-section h2 {\n  color: var(--ink);\n  font-size: 18px;\n  letter-spacing: -0.03em;\n  font-weight: 760;\n  margin: 0;\n}\n\n.install-hero-card p {\n  margin-top: 4px;\n  color: var(--muted);\n  font-size: 14px;\n  line-height: 1.35;\n}\n\n.install-section {\n  margin-top: 14px;\n  padding: 16px;\n  border: 1px solid var(--line);\n  border-radius: 22px;\n  background: var(--surface);\n}\n\n.install-steps {\n  margin: 12px 0 0;\n  padding-left: 22px;\n  color: var(--text);\n  font-size: 15px;\n  line-height: 1.55;\n}\n\n.install-steps li + li {\n  margin-top: 6px;\n}\n\n.install-note {\n  margin-top: 14px;\n  padding: 14px;\n  border: 1px solid var(--line);\n  border-radius: 20px;\n  background: var(--surface-soft);\n  color: var(--muted);\n  font-size: 14px;\n  line-height: 1.4;\n}\n\n.bottom-nav {\n  grid-template-columns: repeat(4, 1fr);\n}\n\n.bottom-nav a {\n  font-size: 12px;\n}\n' + "\n", encoding="utf-8")

print("Icono e instrucciones de instalación añadidos.")
print("Ejecuta: npm run build && git add . && git commit -m 'Add mobile icon and install instructions' && git push && npx vercel --prod")
